/**
 * NPC content entrypoint — catalog generated by scripts/npcs/generate-npc-catalog.mjs
 */

import { NPC_CATALOG_GENERATED } from "@/content/npcs/catalog.generated";
import type { NpcCatalogIndex, NpcDef } from "@/game/npcs/types";

export const NPC_CATALOG: NpcDef[] = NPC_CATALOG_GENERATED;

export const NAMED_NPCS: NpcDef[] = NPC_CATALOG.filter((n) => n.kind === "named");
export const AMBIENT_NPCS: NpcDef[] = NPC_CATALOG.filter((n) => n.kind !== "named");

export const NPC_BY_ID: Record<string, NpcDef> = Object.fromEntries(
  NPC_CATALOG.map((n) => [n.id, n]),
);

export const NPC_BY_SLUG: Record<string, NpcDef> = Object.fromEntries(
  NPC_CATALOG.map((n) => [n.slug, n]),
);

function buildIndex(list: NpcDef[]): NpcCatalogIndex {
  const named = list.filter((n) => n.kind === "named");
  const ambient = list.filter((n) => n.kind !== "named");
  const byId: Record<string, NpcDef> = {};
  const bySlug: Record<string, NpcDef> = {};
  const byRegion: Record<string, NpcDef[]> = {};
  for (const n of list) {
    byId[n.id] = n;
    bySlug[n.slug] = n;
    (byRegion[n.regionId] ??= []).push(n);
  }
  return { named, ambient, byId, bySlug, byRegion };
}

export const NPC_CONTENT_CATALOG = buildIndex(NPC_CATALOG);

export function getNpcById(id: string): NpcDef | undefined {
  return NPC_BY_ID[id];
}

export function getNpcBySlug(slug: string): NpcDef | undefined {
  return NPC_BY_SLUG[slug] ?? NPC_BY_ID[slug];
}

export function npcsForRegion(regionId: string): NpcDef[] {
  return NPC_CONTENT_CATALOG.byRegion[regionId] ?? [];
}

export function listNpcsForRegion(regionId: string): NpcDef[] {
  return npcsForRegion(regionId);
}

export function countNamedInRegion(regionId: string): number {
  return npcsForRegion(regionId).filter((n) => n.kind === "named" && n.active).length;
}

export function countAmbientInRegion(regionId: string): number {
  return npcsForRegion(regionId).filter((n) => n.kind !== "named" && n.active).length;
}

export function npcDefaultLines(npc: NpcDef): string[] {
  const lines = [
    ...(npc.greetingDialogue ?? []),
    ...(npc.repeatDialogue ?? []),
  ].filter((l) => Boolean(l) && !/undefined|null|TODO|placeholder/i.test(l));
  return lines.length ? lines : ["The keeper greets you warmly."];
}
